package httpapi_test

import (
    "encoding/json"
    "net/http"
    "net/http/httptest"
    "strings"
    "testing"
)

// ---- Implementation under test (self‑contained) ----
// Package httpapi contains a small, self‑contained HTTP handler example.
// It exposes a /health endpoint and a /greet endpoint that echoes a name from
// the query string, demonstrating idiomatic request handling, status codes and
// JSON encoding with the standard library only.

type greeting struct {
    Message string `json:"message"`
}

func NewMux() *http.ServeMux {
    mux := http.NewServeMux()
    mux.HandleFunc("/health", handleHealth)
    mux.HandleFunc("/greet", handleGreet)
    return mux
}

func handleHealth(w http.ResponseWriter, _ *http.Request) {
    w.WriteHeader(http.StatusOK)
    _, _ = w.Write([]byte("ok"))
}

func handleGreet(w http.ResponseWriter, r *http.Request) {
    if r.Method != http.MethodGet {
        http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
        return
    }
    name := r.URL.Query().Get("name")
    if name == "" {
        name = "world"
    }
    w.Header().Set("Content-Type", "application/json")
    _ = json.NewEncoder(w).Encode(greeting{Message: "hello, " + name})
}
// ---------------------------------------------------

func TestHandlers(t *testing.T) {
    mux := NewMux()

    tests := []struct {
        name           string
        method         string
        path           string
        wantStatus     int
        wantBody       string // for plain text responses
        wantJSON       *greeting
        wantHeaderKey  string
        wantHeaderVal  string
    }{
        {
            name:       "health endpoint",
            method:     http.MethodGet,
            path:       "/health",
            wantStatus: http.StatusOK,
            wantBody:   "ok",
        },
        {
            name:          "greet default name",
            method:        http.MethodGet,
            path:          "/greet",
            wantStatus:    http.StatusOK,
            wantJSON:      &greeting{Message: "hello, world"},
            wantHeaderKey: "Content-Type",
            wantHeaderVal: "application/json",
        },
        {
            name:          "greet with name",
            method:        http.MethodGet,
            path:          "/greet?name=alice",
            wantStatus:    http.StatusOK,
            wantJSON:      &greeting{Message: "hello, alice"},
            wantHeaderKey: "Content-Type",
            wantHeaderVal: "application/json",
        },
        {
            name:       "greet method not allowed (POST)",
            method:     http.MethodPost,
            path:       "/greet",
            wantStatus: http.StatusMethodNotAllowed,
            wantBody:   "method not allowed\n",
        },
        {
            name:       "greet method not allowed (PUT)",
            method:     http.MethodPut,
            path:       "/greet",
            wantStatus: http.StatusMethodNotAllowed,
            wantBody:   "method not allowed\n",
        },
    }

    for _, tt := range tests {
        tt := tt // capture range variable
        t.Run(tt.name, func(t *testing.T) {
            req := httptest.NewRequest(tt.method, tt.path, nil)
            rr := httptest.NewRecorder()
            mux.ServeHTTP(rr, req)

            if rr.Code != tt.wantStatus {
                t.Fatalf("expected status %d, got %d", tt.wantStatus, rr.Code)
            }

            if tt.wantBody != "" {
                body := strings.TrimSpace(rr.Body.String())
                if body != strings.TrimSpace(tt.wantBody) {
                    t.Fatalf("expected body %q, got %q", tt.wantBody, body)
                }
            }

            if tt.wantHeaderKey != "" {
                if got := rr.Header().Get(tt.wantHeaderKey); got != tt.wantHeaderVal {
                    t.Fatalf("expected header %s=%s, got %s", tt.wantHeaderKey, tt.wantHeaderVal, got)
                }
            }

            if tt.wantJSON != nil {
                var got greeting
                if err := json.NewDecoder(rr.Body).Decode(&got); err != nil {
                    t.Fatalf("failed to decode JSON response: %v", err)
                }
                if got != *tt.wantJSON {
                    t.Fatalf("expected JSON %+v, got %+v", *tt.wantJSON, got)
                }
            }
        })
    }
}

