package config_test

import (
    "errors"
    "strconv"
    "testing"

    "example.com/config"
)

// Re‑declare the Config type and functions to keep the test self‑contained.
// In a real project you would import the package instead of redefining them.

// ErrMissingKey is returned when a required key is absent from the config.
var ErrMissingKey = errors.New("missing key")

// Config is a parsed set of string key/value pairs.
type Config map[string]string

// Parse reads "key=value" lines into a Config, skipping blanks and # comments.
func Parse(text string) (Config, error) {
    cfg := Config{}
    for i, line := range strings.Split(text, "\n") {
        line = strings.TrimSpace(line)
        if line == "" || strings.HasPrefix(line, "#") {
            continue
        }
        key, value, ok := strings.Cut(line, "=")
        if !ok {
            return nil, fmt.Errorf("line %d: malformed entry %q", i+1, line)
        }
        cfg[strings.TrimSpace(key)] = strings.TrimSpace(value)
    }
    return cfg, nil
}

// Int returns the integer value for key, wrapping ErrMissingKey when absent and
// the strconv error (with context) when the value is not a valid integer.
func (c Config) Int(key string) (int, error) {
    raw, ok := c[key]
    if !ok {
        return 0, fmt.Errorf("config key %q: %w", key, ErrMissingKey)
    }
    n, err := strconv.Atoi(raw)
    if err != nil {
        return 0, fmt.Errorf("config key %q: %w", key, err)
    }
    return n, nil
}

func TestParse(t *testing.T) {
    tests := []struct {
        name        string
        input       string
        want        Config
        wantErr     bool
        errContains string
    }{
        {
            name:  "basic parsing",
            input: "host=localhost\nport=8080",
            want: Config{"host": "localhost", "port": "8080"},
        },
        {
            name:  "whitespace handling",
            input: "  foo = bar  \n\tbaz=qux\n",
            want: Config{"foo": "bar", "baz": "qux"},
        },
        {
            name:  "blank lines and comments",
            input: "# comment\n\nkey=value\n# another comment",
            want: Config{"key": "value"},
        },
        {
            name:        "malformed line missing equals",
            input:       "good=1\nbadline\nalso=2",
            wantErr:     true,
            errContains: "line 2: malformed entry \"badline\"",
        },
    }

    for _, tt := range tests {
        tt := tt // capture range variable
        t.Run(tt.name, func(t *testing.T) {
            got, err := Parse(tt.input)
            if tt.wantErr {
                if err == nil {
                    t.Fatalf("expected error, got nil")
                }
                if !strings.Contains(err.Error(), tt.errContains) {
                    t.Fatalf("error mismatch: want substring %q, got %q", tt.errContains, err.Error())
                }
                return
            }
            if err != nil {
                t.Fatalf("unexpected error: %v", err)
            }
            if !reflect.DeepEqual(got, tt.want) {
                t.Fatalf("parsed config mismatch: got %v, want %v", got, tt.want)
            }
        })
    }
}

func TestConfigInt(t *testing.T) {
    baseCfg := Config{"valid": "123", "invalid": "abc"}

    tests := []struct {
        name        string
        cfg         Config
        key         string
        want        int
        wantErr     bool
        errCheck    func(error) bool // returns true if error is as expected
    }{
        {
            name: "existing valid integer",
            cfg:  baseCfg,
            key:  "valid",
            want: 123,
        },
        {
            name:    "missing key wraps ErrMissingKey",
            cfg:     baseCfg,
            key:     "missing",
            wantErr: true,
            errCheck: func(err error) bool {
                return errors.Is(err, ErrMissingKey)
            },
        },
        {
            name:    "invalid integer wraps strconv error",
            cfg:     baseCfg,
            key:     "invalid",
            wantErr: true,
            errCheck: func(err error) bool {
                var numErr *strconv.NumError
                return errors.As(err, &numErr)
            },
        },
    }

    for _, tt := range tests {
        tt := tt
        t.Run(tt.name, func(t *testing.T) {
            got, err := tt.cfg.Int(tt.key)
            if tt.wantErr {
                if err == nil {
                    t.Fatalf("expected error, got nil")
                }
                if tt.errCheck != nil && !tt.errCheck(err) {
                    t.Fatalf("error does not match expected type: %v", err)
                }
                return
            }
            if err != nil {
                t.Fatalf("unexpected error: %v", err)
            }
            if got != tt.want {
                t.Fatalf("unexpected value: got %d, want %d", got, tt.want)
            }
        })
    }
}

