    // Access key "b".
    if v, ok := c.Get("b"); ok {
        fmt.Printf("Get \"b\": %d\n", v)
    } else {
        fmt.Println("Get \"b\": not found")
    }
    c.dump() // now b should be MRU: b:2 c:3

    // Insert another entry, evicting the LRU (c).
    c.Put("d", 4)
    c.dump() // expect d:4 b:2
}
